function convertHTMLToJSON() {
    const htmlString = document.getElementById('htmlInput').value;
    if (!htmlString.trim()) {
        alert('Kripya pehle HTML code paste karein!');
        return;
    }

    const parser = new DOMParser();
    const doc = parser.parseFromString(htmlString, 'text/html');

    const jsonData = {
        head: {
            title: doc.title || "",
            meta: []
        },
        css: {
            internal: [],
            external: []
        },
        body: {
            html: ""
        },
        script: {
            internal: [],
            external: []
        }
    };

    // Parse Meta Tags
    const metas = doc.querySelectorAll('head meta');
    metas.forEach(meta => {
        const metaObj = {};
        if (meta.getAttribute('charset')) metaObj.charset = meta.getAttribute('charset');
        if (meta.getAttribute('name')) metaObj.name = meta.getAttribute('name');
        if (meta.getAttribute('content')) metaObj.content = meta.getAttribute('content');
        if (meta.getAttribute('property')) metaObj.property = meta.getAttribute('property');
        if (Object.keys(metaObj).length > 0) jsonData.head.meta.push(metaObj);
    });

    // Parse CSS (Stylesheets)
    const links = doc.querySelectorAll('link[rel="stylesheet"]');
    links.forEach(link => {
        if (link.getAttribute('href')) jsonData.css.external.push(link.getAttribute('href'));
    });

    const styles = doc.querySelectorAll('style');
    styles.forEach(style => {
        jsonData.css.internal.push(style.innerHTML);
    });

    // Parse Scripts
    const scripts = doc.querySelectorAll('script');
    scripts.forEach(script => {
        const src = script.getAttribute('src');
        if (src) {
            jsonData.script.external.push(src);
        } else {
            jsonData.script.internal.push(script.innerHTML);
        }
    });

    // Parse Body Content (Bina script aur style tags ke)
    const bodyClone = doc.body.cloneNode(true);
    const removeTags = bodyClone.querySelectorAll('script, style');
    removeTags.forEach(tag => tag.remove());
    jsonData.body.html = bodyClone.innerHTML;

    // Display Result
    document.getElementById('jsonOutput').innerText = JSON.stringify(jsonData, null, 4);
}

function copyJSON() {
    const jsonText = document.getElementById('jsonOutput').innerText;
    if (jsonText === "JSON output yahaan dikhega..." || !jsonText) {
        alert("Pehle HTML ko convert karein!");
        return;
    }
    navigator.clipboard.writeText(jsonText).then(() => {
        alert("JSON successfully copy ho gaya!");
    }).catch(err => {
        alert("Copy karne mein dikkat hui: ", err);
    });
}
